const { pedidos } = $input.first().json;

const ahora = new Date();
const hoy = ahora.toISOString();

// Fecha inicio de semana anterior (lunes pasado)
const lunesAnterior = new Date(ahora);
lunesAnterior.setDate(ahora.getDate() - 7);
lunesAnterior.setHours(0,0,0,0);

// Pedidos activos (no enviado-final)
const activos = pedidos.filter(p => p.estado !== 'enviado-final');

// Entregados esta semana
const entregados = pedidos.filter(p =>
  p.estado === 'enviado-final' &&
  p.ultimoMovimiento &&
  new Date(p.ultimoMovimiento) >= lunesAnterior
);

// Por estado
const estados = {
  'bandeja': 0, 'hacer-diseno': 0, 'confirmado': 0,
  'enviado-calandra': 0, 'llego-impresion': 0, 'corte': 0,
  'calidad': 0, 'costura': 0, 'listo': 0
};
activos.forEach(p => {
  if (estados[p.estado] !== undefined) estados[p.estado]++;
});

// Sin movimiento +3 días
const sinMovimiento = activos.filter(p => {
  if (!p.ultimoMovimiento) return false;
  const diff = (ahora - new Date(p.ultimoMovimiento)) / (1000 * 60 * 60 * 24);
  return diff >= 3;
});

// Vencidos (fecha entrega pasada)
const vencidos = activos.filter(p => {
  if (!p.fechaEntrega) return false;
  const partes = p.fechaEntrega.split('/');
  if (partes.length !== 3) return false;
  const fecha = new Date(`${partes[2]}-${partes[1]}-${partes[0]}`);
  return fecha < ahora;
});

// Armar líneas sin movimiento
const listaSinMov = sinMovimiento.slice(0, 5).map(p => {
  const dias = Math.floor((ahora - new Date(p.ultimoMovimiento)) / (1000*60*60*24));
  return `  • ${p.equipo || 'Sin nombre'} — ${p.estado} (${dias}d)`;
}).join('\n');

// Armar líneas vencidos
const listaVencidos = vencidos.slice(0, 5).map(p =>
  `  • ${p.equipo || 'Sin nombre'} — venció ${p.fechaEntrega}`
).join('\n');

const texto = `📊 *Reporte Semanal Producción*
📅 Semana del ${lunesAnterior.toLocaleDateString('es-CO')} al ${ahora.toLocaleDateString('es-CO')}

✅ *Entregados esta semana:* ${entregados.length}
📦 *Pedidos activos:* ${activos.length}

📋 *Por etapa:*
  Bandeja: ${estados['bandeja']}
  Diseño: ${estados['hacer-diseno']}
  Confirmado: ${estados['confirmado']}
  Calandra: ${estados['enviado-calandra']}
  Impresión: ${estados['llego-impresion']}
  Corte: ${estados['corte']}
  Calidad: ${estados['calidad']}
  Costura: ${estados['costura']}
  Listo: ${estados['listo']}

⚠️ *Sin movimiento +3 días:* ${sinMovimiento.length}
${listaSinMov || '  Ninguno'}

🔴 *Vencidos:* ${vencidos.length}
${listaVencidos || '  Ninguno'}`;

return [{ json: { texto } }];
